#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


vec3 stak,vs;
vec2 tr,aspx;
vec2 st,pq;
float i=0.94;
float my_smp=texture(sampler_pc_main,vec2(q20,i)).x*2;
aspx=vec2(q2,q1);
pq=((vUv-0.5)*aspx+0.5);
st=vec2(q3,q4);
vec3 v;
v.xy=pq-st;
v.z=0.1;
float  d=length(v);
float  m=2;
v=normalize(v);

tr=v.xy*sin(d*m*M_PI_2+my_smp*M_PI_2)*v.zz*v.zz;

vs.xy=tr.xy;
tr=tr;
vs.z=d;
vs.xy=v.xy*my_smp*v.zz;

i=0.9;
my_smp=texture(sampler_pc_main,vec2(q20,i)).x;
st=vec2(q5,q6);
v.xy=pq-st;
v.z=0.2;
d=length(v);
m=6;
v=normalize(v);
tr=v.xy*sin(my_smp*M_PI_2+d*m*M_PI_2)*v.zz*v.zz;
vs.z+=d;


vs.xy+=v.xy*my_smp*v.zz;

i=0.85;
my_smp=texture(sampler_pc_main,vec2(q20,i)).x;
st=vec2(q7,q8);
v.xy=pq-st;
v.z=0.3;
d=length(v);
m=14;
v=normalize(v);
tr=v.xy*sin(my_smp*M_PI_2+d*m*M_PI_2)*v.zz*v.zz;
vs.z+=d;
vs.xy+=v.xy*my_smp*v.zz;

i=0.8;
my_smp=texture(sampler_pc_main,vec2(q20,i)).x;
st=vec2(q9,q10);
v.xy=pq-st;
v.z=0.4;
d=length(v);
m=30;
v=normalize(v);
tr=v.xy*sin(my_smp*M_PI_2+d*m*M_PI_2)*v.zz*v.zz;
vs.z+=d;

vs.xy+=v.xy*my_smp*v.zz;

i=0.75;
my_smp=texture(sampler_pc_main,vec2(q20,i)).x;
st=vec2(q11,q12);
v.xy=pq-st;
v.z=0.5;
d=length(v);
m=64;
v=normalize(v);
tr=v.xy*sin(my_smp*M_PI_2+d*m*M_PI_2)*v.zz*v.zz;
vs.z+=d;
vs.xy+=v.xy*my_smp*v.zz;

i=0.6;
my_smp=texture(sampler_pc_main,vec2(q20,i)).x;
st=vec2(q13,q14);
v.xy=pq-st;
v.z=0.6;
d=length(v);
m=120;
v=normalize(v);
tr=v.xy*sin(my_smp*M_PI_2+d*m*M_PI_2)*v.zz*v.zz;
vs.z+=d;
vs.xy+=v.xy*my_smp*v.zz;

i=0.35;
my_smp=texture(sampler_pc_main,vec2(q20,i)).x;
st=vec2(q15,q16);
v.xy=pq-st;
v.z=0.7;
d=length(v);
m=200;
v=normalize(v);
tr=v.xy*sin(my_smp*M_PI_2+d*m*M_PI_2)*v.zz*v.zz;
vs.z+=d;
vs.xy+=v.xy*my_smp*v.zz;

i=0.2;
my_smp=texture(sampler_pc_main,vec2(q20,i)).x;
st=vec2(q17,q18);
v.xy=pq-st;
v.z=0.8;
d=length(v);
m=280;
v=normalize(v);
tr=v.xy*sin(my_smp*M_PI_2+d*m*M_PI_2)*v.zz*v.zz;
vs.z+=d;
vs.xy+=v.xy*my_smp*v.zz;

ret.xyz=texture(sampler_rand00,((vUv-0.5)*vs.zz*aspx+0.5)+(8-vs.zz)*vs.xy*0.02*aspx).xyz;//*0.025;
vec3 disto =texture(sampler_main,vUv-vs.xy*0.02*vs.zz/aspx).xyz;//*0.975);

ret=disto*0.98+ret*0.02;//1-(1/(1+vs.z*vs.z)));



  fragColor = ret;
}

